  ('pukao-6f0ba476-moex-00299', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '加值型及非加值型營業稅法，有關小規模營業人之課稅規定，下列敘述何者正確？', '["依加值型方式計算稅額，但進項稅額不得扣抵", "依加值型方式計算稅額，但進項稅額僅能扣抵10%", "符合相關條件並依規定申報者，主管稽徵機關應按其進項稅額20%，在查定稅額內扣減", "符合相關條件並依規定申報者，主管稽徵機關應按其進項稅額10%，在查定稅額內扣減"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00300', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依據我國加值型及非加值型營業稅法第3條之規定，下列敘述何者錯誤？', '["營業人以其產製、進口、購買供銷售之貨物，轉供營業人自用，無須視為銷售開立發票", "營業人解散或廢止營業時所餘存之貨物，或將貨物抵償債務、分配與股東或出資人者，須視為 銷售開立發票", "營業人以其產製、進口、購買之貨物，無償移轉他人所有者，須視為銷售開立發票", "營業人銷售代銷貨物者須視為銷售開立發票"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00301', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依據我國加值型及非加值型營業稅法之規定，下列進口貨物何者不符合免徵營業稅之規定？', '["進口本國之古物", "進口肥料", "進口金條、金塊、金片、金幣", "進口未經加工之生鮮農、林、漁、牧產物"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00302', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '父親將名下100張興櫃股票贈與給女兒，應以下列何項標準計算其贈與之財產價值？', '["該股票淨值", "該股票之承銷價格", "該股票當日收盤價格", "該股票當日加權平均成交價格"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00303', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '土地所有權人因重購土地退還土地增值稅，其重購之土地自完成移轉登記之日起 5 年內再行移 轉時，應如何處理？', '["就該次移轉之漲價總數額課徵土地增值稅外，並處1倍罰鍰", "就該次移轉之漲價總數額課徵2倍之土地增值稅，但不追繳原退還稅款", "就該次移轉之漲價總數額課徵土地增值稅外，並應追繳原退還稅款", "就該次移轉之漲價總數額課徵土地增值稅外，並應追繳原退還稅額之2倍稅款"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00304', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '土地增值稅若符合長期持有減徵之規定，則至少須持有超過幾年？', '["3年", "5年", "10年", "20年"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00305', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依據我國土地稅法之規定，土地為信託財產者，於信託關係存續中，以下列何者為地價稅或田賦 之納稅義務人？', '["委託人", "受託人", "受益人", "共有人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00306', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '美國籍的王牧師係屬於經常居住中華民國境內傳道之非中華民國國民，後因年事已高，於 民國 111年5月病逝於中華民國境內，下列有關王牧師遺產稅課徵之敘述何者正確？', '["王牧師死亡前二年經常居住在中華民國境內，因此應就其在中華民國境內、境外全部遺產課徵 遺產稅", "王牧師在臺灣期間所投資的美國蘋果公司股票係屬於其境內財產", "王牧師遺有配偶，故可以自其遺產總額中扣除493萬元", "王牧師的繼承人得自其遺產總額中減除本人免稅額1,333萬元"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00307', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '依據我國土地稅法之規定，欲適用一生一次自用住宅用地土地增值稅優惠稅率之規定，下列敘述 何者錯誤？', '["本法所稱自用住宅用地，指土地所有權人或其配偶、直系親屬於該地辦竣戶籍登記，且無出租 或供營業用之住宅用地", "必須於出售時土地所有權人與其配偶及未成年子女，無該自用住宅以外之房屋，方可適用", "必須於出售前一年內，未曾供營業使用或出租者", "其土地增值稅就土地漲價總數額按百分之十稅率徵收之"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('pukao-6f0ba476-moex-00308', 'pukao-6f0ba476', 'pukao-6f0ba476-moex-111-e38ac4c6', 'sub-pukao-6f0ba476-03', NULL, 'single_choice', '不動產因下列那些方式取得者，其契稅稅率為6%？', '["交換、典權、分割", "交換、占有、分割", "買賣、贈與、占有", "買賣、贈與、繼承"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:46+00:00", "source_pdf_sha1": "3891130ea53d", "answer_pdf_sha1": "2196a9090a26", "source_family": "moex-gov-tw", "moex": {"exam_code": "111090", "c": "414", "s": "0907", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "稅務法規概要", "year": "111", "exam_name": "111年公務人員高等考試三級考試暨普通考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "財稅行政"}'::jsonb, NULL)
